patch:
--- a/register_file.sv
+++ b/register_file.sv
@@ -1,16 +1,16 @@
 module reg_file(
   input clk,
   input [4:0] rd_addr,
   input [4:0] wr_addr,
   input [31:0] wr_data,
-  output [31:0] rd_data
+  output [31:0] rd_data,
+  input wr_en
 );
   reg [31:0] registers [31:0];

   always @(posedge clk) begin
     if (wr_en) registers[wr_addr] <= wr_data;
   end
   assign rd_data = registers[rd_addr];
 endmodule

 module cpu(
@@ -18,7 +18,7 @@
   input [31:0] write_value,
   output [31:0] read_value
 );
-  reg_file rf(.rd_addr(raddr), .wr_addr(waddr), .wr_data(write_value), .rd_data(read_value), .clk(clk));
+  reg_file rf(.rd_addr(raddr), .wr_addr(waddr), .wr_data(write_value), .rd_data(read_value), .clk(clk), .wr_en(1'b1));
 endmodule

before_code:
module reg_file(
  input clk,
  input [4:0] rd_addr,
  input [4:0] wr_addr,
  input [31:0] wr_data,
  output [31:0] rd_data
);
  reg [31:0] registers [31:0];

  always @(posedge clk) begin
    if (wr_en) registers[wr_addr] <= wr_data;
  end
  assign rd_data = registers[rd_addr];
endmodule

module cpu(
  input clk,
  input [4:0] raddr, waddr,
  input [31:0] write_value,
  output [31:0] read_value
);
  reg_file rf(.rd_addr(raddr), .wr_addr(waddr), .wr_data(write_value), .rd_data(read_value), .clk(clk));
endmodule

after_code:
module reg_file(
  input clk,
  input [4:0] rd_addr,
  input [4:0] wr_addr,
  input [31:0] wr_data,
  output [31:0] rd_data,
  input wr_en
);
  reg [31:0] registers [31:0];

  always @(posedge clk) begin
    if (wr_en) registers[wr_addr] <= wr_data;
  end
  assign rd_data = registers[rd_addr];
endmodule

module cpu(
  input clk,
  input [4:0] raddr, waddr,
  input [31:0] write_value,
  output [31:0] read_value
);
  reg_file rf(.rd_addr(raddr), .wr_addr(waddr), .wr_data(write_value), .rd_data(read_value), .clk(clk), .wr_en(1'b1));
endmodule
